    16→/// Exponential backoff strategy with jitter to prevent thundering herd
    17→///
    18→/// This strategy exponentially increases the delay between retries based on
    19→/// the attempt count, with added randomness (jitter) to prevent multiple
    20→/// operations from retrying at the exact same time.
    21→///
    22→/// Formula: min(baseDelay * 2^attemptCount + jitter, maxDelay)
    23→class ExponentialBackoffStrategy extends RetryStrategy {
    24→  /// The base delay before the first retry
    25→  final Duration baseDelay;
    26→
    27→  /// The maximum delay cap to prevent excessively long waits
    28→  final Duration maxDelay;
    29→
    30→  /// Jitter factor as a percentage (0.0 to 1.0)
    31→  /// Default 0.1 means up to 10% random variation
    32→  final double jitterFactor;
    33→
    34→  /// Random number generator for jitter calculation
    35→  final Random _random;
    36→
    37→  /// Creates an exponential backoff strategy
    38→  ///
    39→  /// [baseDelay] The starting delay (default: 1 second)
    40→  /// [maxDelay] The maximum allowed delay (default: 5 minutes)
    41→  /// [jitterFactor] Random variation as percentage 0.0-1.0 (default: 0.1)
    42→  /// [random] Optional custom random generator (for testing)
    43→  const ExponentialBackoffStrategy({
    44→    this.baseDelay = const Duration(seconds: 1),
    45→    this.maxDelay = const Duration(minutes: 5),
    46→    this.jitterFactor = 0.1,
    47→    Random? random,
    48→  })  : _random = random ?? const Random._internal(0),
    49→        assert(jitterFactor >= 0.0 && jitterFactor <= 1.0,
    50→            'jitterFactor must be between 0.0 and 1.0');
    51→
    52→  @override
    53→  Duration calculateDelay(int attemptCount) {
    54→    if (attemptCount < 0) {
    55→      debugPrint('ExponentialBackoffStrategy: attemptCount cannot be negative, defaulting to 0');
    56→      attemptCount = 0;
    57→    }
    58→
    59→    // Calculate exponential backoff: baseDelay * 2^attemptCount
    60→    final exponentialDelay = baseDelay.inMilliseconds * pow(2, attemptCount);
    61→
    62→    // Calculate jitter: random value between -jitterFactor and +jitterFactor
    63→    final jitterRange = exponentialDelay * jitterFactor;
    64→    final jitter = (_random.nextDouble() * 2 - 1) * jitterRange;
    65→
    66→    // Apply jitter and ensure we don't go below zero
    67→    final delayWithJitter = max(0, (exponentialDelay + jitter).round());
    68→
    69→    // Cap at maxDelay to prevent excessively long waits
    70→    final cappedDelay = min(delayWithJitter, maxDelay.inMilliseconds);
    71→
    72→    final result = Duration(milliseconds: cappedDelay);
    73→
    74→    debugPrint(
    75→      'ExponentialBackoffStrategy: attempt #$attemptCount -> ${result.inSeconds}s '
    76→      '(base: ${baseDelay.inSeconds}s, exponential: ${(exponentialDelay / 1000).toStringAsFixed(2)}s, '
    77→      'jitter: ${(jitter / 1000).toStringAsFixed(2)}s)'
    78→    );
    79→
    80→    return result;
    81→  }
    82→
    83→  @override
